import React, { useState, useRef, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import LoginModal from '../Auth/LoginModal';
import RegisterModal from '../Auth/RegisterModal';
import './UserMenu.css';
import { FaUser, FaSignOutAlt, FaCog, FaBook, FaUserShield } from 'react-icons/fa';

const UserMenu = () => {
  const { user, logout, isAdmin } = useAuth();
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [showRegisterModal, setShowRegisterModal] = useState(false);
  const [showDropdown, setShowDropdown] = useState(false);
  const dropdownRef = useRef(null);

  // Click outside to close dropdown
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setShowDropdown(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  const handleLogout = () => {
    logout();
    setShowDropdown(false);
  };

  return (
    <>
      <div className="user-menu-container" ref={dropdownRef}>
        {user ? (
          <div 
            className="user-profile"
            onClick={() => setShowDropdown(!showDropdown)}
          >
            <div className="user-avatar">
              {user.avatar ? (
                <img src={user.avatar} alt={user.username} />
              ) : (
                <FaUser />
              )}
            </div>
            <span className="user-name">{user.username}</span>
            
            {showDropdown && (
              <div 
                className="user-dropdown"
                onClick={(e) => e.stopPropagation()}
              >
                <div className="user-info">
                  <div className="user-level">Уровень: {user.level}</div>
                  <div className="user-points">Очки: {user.points}</div>
                  {isAdmin() && (
                    <div className="user-role admin-badge">
                      <i className="fas fa-crown"></i> Администратор
                    </div>
                  )}
                </div>
                <Link to="/profile" className="dropdown-item" onClick={() => setShowDropdown(false)}>
                  <FaUser /> Профиль
                </Link>
                <Link to="/library" className="dropdown-item" onClick={() => setShowDropdown(false)}>
                  <FaBook /> Моя библиотека
                </Link>
                
                {/* Admin panel linki */}
                {isAdmin() && (
                  <Link to="/admin" className="dropdown-item admin-link" onClick={() => setShowDropdown(false)}>
                    <FaUserShield /> Админ-панель
                  </Link>
                )}
                
                <Link to="/settings" className="dropdown-item" onClick={() => setShowDropdown(false)}>
                  <FaCog /> Настройки
                </Link>
                <button onClick={handleLogout} className="dropdown-item logout">
                  <FaSignOutAlt /> Выйти
                </button>
              </div>
            )}
          </div>
        ) : (
          <div className="auth-buttons">
            <button 
              className="login-btn"
              onClick={() => setShowLoginModal(true)}
            >
              Вход
            </button>
            <button 
              className="register-btn"
              onClick={() => setShowRegisterModal(true)}
            >
              Регистрация
            </button>
          </div>
        )}
      </div>

      {showLoginModal && (
        <LoginModal 
          onClose={() => setShowLoginModal(false)}
          onSwitchToRegister={() => {
            setShowLoginModal(false);
            setShowRegisterModal(true);
          }}
        />
      )}

      {showRegisterModal && (
        <RegisterModal 
          onClose={() => setShowRegisterModal(false)}
          onSwitchToLogin={() => {
            setShowRegisterModal(false);
            setShowLoginModal(true);
          }}
        />
      )}
    </>
  );
};

export default UserMenu;
